
import { defineComponent } from 'vue';
import vClickOutside from '../click-outside';

export default defineComponent({
	Name: 'MobileNavBar',
	data() {
		return {
			display: false
		}
	},
	methods: {
		toggleDisplay : function() {
			this.display = !this.display;
		},
		onClickOutside: function () {
        this.display = false;
		},
	},
	directives: {
      clickOutside: vClickOutside
    },
});
